/// Minecraft block-type index for a block-state id (binary search over runs).
pub fn name_index_for_state(id: u32) -> u16 {
    if id > MAX_STATE {
        return 0;
    }
    let mut lo = 0usize;
    let mut hi = STATE_RUNS.len();
    while lo + 1 < hi {
        let mid = (lo + hi) / 2;
        if STATE_RUNS[mid].0 <= id {
            lo = mid;
        } else {
            hi = mid;
        }
    }
    STATE_RUNS[lo].1
}

/// The MineRust block that best approximates a Minecraft block-state id.
pub fn block_for_state(id: u32) -> Block {
    PHYS[name_index_for_state(id) as usize]
}

/// The MineRust block for a Minecraft block-type index.
#[allow(dead_code)]
pub fn block_for_index(i: u16) -> Block {
    PHYS[i as usize]
}
